1	//! Which side(s) of a workspace a command should operate on.
2	//!
3	//! - `Side` is the clap `ValueEnum` — one of `code`, `bot`.
4	//! - `Scope` is an enum:
5	//!   - `Roles(Vec<Side>)` — dual-repo workspace; the parsed
6	//!     keyword form (`code`, `bot`, `code,bot`, `bot,code`).
7	//!   - `Single(PathBuf)` — explicit single-repo mode; ignores
8	//!     `.vc-config.toml` and operates on the one repo at the
9	//!     given path.
10	//! - Helpers (`has_code`, `is_both`, etc.) reflect the `Roles`
11	//!   arm only; on `Single(_)` they all return `false`. Callers
12	//!   that must distinguish modes match on the enum directly.
13	//! - See `notes/chores/chores-07.md > --scope enum refactor (0.42.0)`
14	//!   for the migration plan, and `notes/chores/chores-06.md > 0.41.0-4`
15	//!   for the vocabulary capture.
16	
17	use clap::ValueEnum;
18	use std::fmt;
19	use std::path::PathBuf;
20	
21	/// One side of a dual-repo workspace.
22	///
23	/// - `Code` — the primary (app) repo.
24	/// - `Bot` — the Claude Code session repo (typically at `.claude/`).
25	#[derive(Copy, Clone, Debug, PartialEq, Eq, ValueEnum)]
26	pub enum Side {
27	    Code,
28	    Bot,
29	}
30	
31	/// Parsed `--scope` value.
32	///
33	/// - `Roles(_)` — dual-repo workspace; the requested side set.
34	/// - `Single(_)` — explicit single-repo mode at the given path.
35	#[derive(Clone, Debug, PartialEq, Eq)]
36	pub enum Scope {
37	    Roles(Vec<Side>),
38	    Single(PathBuf),
39	}
40	
41	/// Parse a `--scope` value string.
42	///
43	/// Accepted forms:
44	///
45	/// - Keyword: exactly one of `code`, `bot`, `code,bot`, `bot,code`
46	///   → `Scope::Roles(...)`. Order is preserved.
47	/// - Path: starts with `./`, `../`, `/`, `~/`, or is the bare `~`
48	///   → `Scope::Single(PathBuf)`. The raw string is stored; tilde
49	///   and `$VAR` expansion happens at the consumer (see
50	///   `init::expand_vars`).
51	///
52	/// Anything else — including a bare unprefixed name like `foo`, an
53	/// empty string, or an unrecognized keyword combination — is an
54	/// error. The error message hints at the path-prefix requirement
55	/// so users see the disambiguation rule when they mistype.
56	pub fn parse_scope(s: &str) -> Result<Scope, String> {
57	    if s == "~"
58	        || s.starts_with("./")
59	        || s.starts_with("../")
60	        || s.starts_with('/')
61	        || s.starts_with("~/")
62	    {
63	        return Ok(Scope::Single(PathBuf::from(s)));
64	    }
65	    match s {
66	        "code" => Ok(Scope::Roles(vec![Side::Code])),
67	        "bot" => Ok(Scope::Roles(vec![Side::Bot])),
68	        "code,bot" => Ok(Scope::Roles(vec![Side::Code, Side::Bot])),
69	        "bot,code" => Ok(Scope::Roles(vec![Side::Bot, Side::Code])),
70	        "" => Err("--scope: value is empty".into()),
71	        other => Err(format!(
72	            "--scope: '{other}' is not a recognized form. \
73	             Expected one of `code`, `bot`, `code,bot`, `bot,code`, \
74	             or a path (`./X`, `../X`, `/X`, `~/X`). \
75	             Bare names without `./` are reserved for keywords; \
76	             prefix paths with `./` to disambiguate."
77	        )),
78	    }
79	}
80	
81	/// Parse `--scope` value, accepting only role keywords today.
82	///
83	/// Wraps [`parse_scope`] and rejects the path forms (`./X`, `../X`,
84	/// `/X`, `~`, `~/X`) with a hint pointing users at `-R`/`--repo` for
85	/// single-path operation. Path-via-`--scope` (including the planned
86	/// `--scope=<path>,bot,code` workspace-root override) is a future
87	/// feature tracked in `notes/todo.md`; keeping the path branch in
88	/// `parse_scope` itself avoids re-implementing the disambiguation
89	/// when that feature lands.
90	pub fn parse_scope_roles(s: &str) -> Result<Scope, String> {
91	    match parse_scope(s)? {
92	        Scope::Single(_) => Err(format!(
93	            "--scope: '{s}' looks like a path; path-via-`--scope` isn't \
94	             supported yet (planned). Use `-R/--repo <path>` for \
95	             single-repo operation, or `--scope=code|bot|code,bot` for \
96	             role-based selection."
97	        )),
98	        scope => Ok(scope),
99	    }
100	}
101	
102	impl Scope {
103	    /// True when the `Roles` arm includes the code side.
104	    pub fn has_code(&self) -> bool {
105	        matches!(self, Scope::Roles(v) if v.contains(&Side::Code))
106	    }
107	
108	    /// True when the `Roles` arm includes the bot side.
109	    pub fn has_bot(&self) -> bool {
110	        matches!(self, Scope::Roles(v) if v.contains(&Side::Bot))
111	    }
112	
113	    /// Roles-only with exactly the code side — single-side dual-repo op.
114	    pub fn is_code_only(&self) -> bool {
115	        self.has_code() && !self.has_bot()
116	    }
117	
118	    /// Roles-only with exactly the bot side — single-side dual-repo op.
119	    #[allow(dead_code)]
120	    pub fn is_bot_only(&self) -> bool {
121	        !self.has_code() && self.has_bot()
122	    }
123	
124	    /// Roles arm including both sides — full dual-repo op.
125	    pub fn is_both(&self) -> bool {
126	        self.has_code() && self.has_bot()
127	    }
128	}
129	
130	/// Render a `Scope` as the canonical string form `parse_scope` accepts.
131	///
132	/// - `Roles(_)` → `code` / `bot` / `code,bot` / `bot,code` (preserves
133	///   original side ordering).
134	/// - `Single(p)` → the path's lossy display form. The stored path
135	///   already carries a parser-recognized prefix (the parser is the
136	///   only constructor of `Single`), so the round-trip through
137	///   `parse_scope` is well-defined.
138	impl fmt::Display for Scope {
139	    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
140	        match self {
141	            Scope::Roles(sides) => {
142	                let parts: Vec<&'static str> = sides
143	                    .iter()
144	                    .map(|s| match s {
145	                        Side::Code => "code",
146	                        Side::Bot => "bot",
147	                    })
148	                    .collect();
149	                f.write_str(&parts.join(","))
150	            }
151	            Scope::Single(p) => write!(f, "{}", p.display()),
152	        }
153	    }
154	}
155	
156	#[cfg(test)]
157	mod tests {
158	    use super::*;
159	
160	    #[test]
161	    fn code_only() {
162	        let s = Scope::Roles(vec![Side::Code]);
163	        assert!(s.is_code_only());
164	        assert!(!s.is_bot_only());
165	        assert!(!s.is_both());
166	    }
167	
168	    #[test]
169	    fn bot_only() {
170	        let s = Scope::Roles(vec![Side::Bot]);
171	        assert!(!s.is_code_only());
172	        assert!(s.is_bot_only());
173	        assert!(!s.is_both());
174	    }
175	
176	    #[test]
177	    fn both_code_then_bot() {
178	        let s = Scope::Roles(vec![Side::Code, Side::Bot]);
179	        assert!(!s.is_code_only());
180	        assert!(!s.is_bot_only());
181	        assert!(s.is_both());
182	    }
183	
184	    #[test]
185	    fn both_bot_then_code() {
186	        // Order doesn't matter — contains-based checks.
187	        let s = Scope::Roles(vec![Side::Bot, Side::Code]);
188	        assert!(s.is_both());
189	    }
190	
191	    #[test]
192	    fn empty_roles() {
193	        // Empty side list isn't a state anything constructs (the
194	        // parser rejects empty input), but the helpers still need
195	        // to be well-defined on it.
196	        let s = Scope::Roles(vec![]);
197	        assert!(!s.is_code_only());
198	        assert!(!s.is_bot_only());
199	        assert!(!s.is_both());
200	    }
201	
202	    #[test]
203	    fn single_helpers_all_false() {
204	        // `Single(_)` is a distinct mode; the Roles-shaped helpers
205	        // all report false so callers that match on helpers
206	        // naturally fall through to mode-aware logic.
207	        let s = Scope::Single(PathBuf::from("/some/repo"));
208	        assert!(!s.has_code());
209	        assert!(!s.has_bot());
210	        assert!(!s.is_code_only());
211	        assert!(!s.is_bot_only());
212	        assert!(!s.is_both());
213	    }
214	
215	    // ---------- parse_scope ----------
216	
217	    #[test]
218	    fn parse_keyword_code() {
219	        assert_eq!(parse_scope("code").unwrap(), Scope::Roles(vec![Side::Code]));
220	    }
221	
222	    #[test]
223	    fn parse_keyword_bot() {
224	        assert_eq!(parse_scope("bot").unwrap(), Scope::Roles(vec![Side::Bot]));
225	    }
226	
227	    #[test]
228	    fn parse_keyword_code_bot_preserves_order() {
229	        assert_eq!(
230	            parse_scope("code,bot").unwrap(),
231	            Scope::Roles(vec![Side::Code, Side::Bot])
232	        );
233	    }
234	
235	    #[test]
236	    fn parse_keyword_bot_code_preserves_order() {
237	        assert_eq!(
238	            parse_scope("bot,code").unwrap(),
239	            Scope::Roles(vec![Side::Bot, Side::Code])
240	        );
241	    }
242	
243	    #[test]
244	    fn parse_path_dotslash() {
245	        assert_eq!(
246	            parse_scope("./foo").unwrap(),
247	            Scope::Single(PathBuf::from("./foo"))
248	        );
249	    }
250	
251	    #[test]
