26	/// Result of parsing positional `..` notation.
27	///
28	/// Counts are `Some(0)` for closed sides and `None` for open (dotted) sides.
29	/// Open sides become unlimited unless a positional count is applied later.
30	#[derive(Debug, Clone, PartialEq, Eq)]
31	pub struct DotSpec {
32	    /// The bare revision (without `..`).
33	    pub rev: String,
34	    /// Descendant count: `None` = open (dotted), `Some(0)` = closed.
35	    pub desc_count: Option<usize>,
36	    /// Ancestor count: `None` = open (dotted), `Some(0)` = closed.
