330	/// Collect commit IDs for `..x..` (both directions) or any dot notation.
331	///
332	/// Returns `(commit_ids, anchor_index)` — the IDs in display order
333	/// (descendants closest to anchor, anchor, ancestors closest to anchor)
334	/// and the index of the anchor commit within the list.
335	///
336	/// - `desc_count`: `Some(n)` = n closest descendants, `None` = all, `Some(0)` = none
337	/// - `anc_count`: `Some(n)` = n closest ancestors, `None` = all, `Some(0)` = none
338	pub fn collect_ids(
339	    workspace: &Workspace,
340	    repo: &Arc<ReadonlyRepo>,
341	    rev: &str,
342	    desc_count: Option<usize>,
343	    anc_count: Option<usize>,
344	) -> Result<(Vec<CommitId>, usize), Box<dyn std::error::Error>> {
345	    let anchor_ids = resolve_revset(workspace, repo, rev)?;
346	    if anchor_ids.is_empty() {
347	        return Err(format!("no commit found for revision '{rev}'").into());
348	    }
349	    let anchor_id = &anchor_ids[0];
350	    let root_commit_id = repo.store().root_commit_id().clone();
351	
352	    // Descendants (closest to anchor)
353	    let mut desc_ids: Vec<CommitId> = Vec::new();
354	    if desc_count != Some(0) {
355	        let descendant_ids = resolve_revset(workspace, repo, &format!("{rev}::"))?;
356	        desc_ids = descendant_ids
357	            .into_iter()
358	            .filter(|id| *id != root_commit_id && *id != *anchor_id)
359	            .collect();
360	        if let Some(n) = desc_count {
361	            let start = desc_ids.len().saturating_sub(n);
362	            desc_ids = desc_ids[start..].to_vec();
363	        }
364	    }
365	
366	    // Ancestors (closest to anchor)
367	    let mut anc_ids: Vec<CommitId> = Vec::new();
368	    if anc_count != Some(0) {
369	        let ancestor_ids = resolve_revset(workspace, repo, &format!("::{rev}"))?;
370	        let limit = anc_count.unwrap_or(usize::MAX); // OK: no --ancestors limit → unbounded
371	        let mut count = 0;
372	        for commit_id in ancestor_ids {
373	            if commit_id == root_commit_id || commit_id == *anchor_id {
374	                continue;
375	            }
376	            anc_ids.push(commit_id);
377	            count += 1;
378	            if count >= limit {
379	                break;
380	            }
381	        }
382	    }
383	
384	    let anchor_index = desc_ids.len();
385	    let mut result = desc_ids;
386	    result.push(anchor_id.clone());
387	    result.extend(anc_ids);
388	    Ok((result, anchor_index))
389	}
