403	pub fn resolve_header(label: &str, suppress: bool) -> Header {
404	    if suppress {
405	        Header::None
406	    } else {
407	        Header::Label(label.to_string())
408	    }
409	}
410	
411	/// Run a closure once per resolved repo, with optional header decoration between repos.
412	///
413	/// Takes an already-resolved `&[PathBuf]` — the caller is responsible
414	/// for any flag-driven expansion (see `resolve_repos`). Continues past
415	/// errors, printing them to stderr, and returns an error if any
416	/// repo's body failed.
417	pub fn for_each_repo<F>(
418	    repos: &[PathBuf],
419	    header: &Header,
420	    mut body: F,
421	) -> Result<(), Box<dyn std::error::Error>>
422	where
423	    F: FnMut(&Workspace, &Arc<ReadonlyRepo>) -> Result<(), Box<dyn std::error::Error>>,
424	{
425	    let multi = repos.len() > 1;
426	    let mut first = true;
427	    let mut errors: Vec<String> = Vec::new();
428	
429	    for repo_path in repos {
430	        if multi {
431	            match header {
432	                Header::Label(deco) => {
433	                    if !first {
434	                        info!("");
435	                    }
436	                    info!(
437	                        "{}",
438	                        bold(&format!("{deco} {} {deco}", repo_path.display()))
439	                    );
440	                }
441	                Header::None => {}
442	            }
443	        }
444	        first = false;
445	
446	        match load_repo(repo_path) {
447	            Ok((workspace, repo)) => {
448	                if let Err(e) = body(&workspace, &repo) {
449	                    error!("({}): {e}", repo_path.display());
450	                    errors.push(format!("{}: {e}", repo_path.display()));
451	                }
452	            }
453	            Err(e) => {
454	                error!("({}): {e}", repo_path.display());
455	                errors.push(format!("{}: {e}", repo_path.display()));
456	            }
457	        }
458	    }
459	
460	    if errors.is_empty() {
461	        Ok(())
462	    } else {
463	        Err(format!("{} repo(s) had errors", errors.len()).into())
464	    }
465	}
466	
467	pub fn load_repo(
468	    path: &Path,
469	) -> Result<(Workspace, Arc<ReadonlyRepo>), Box<dyn std::error::Error>> {
470	    let config = StackedConfig::with_defaults();
471	    let settings = UserSettings::from_config(config)?;
472	    let store_factories = StoreFactories::default();
473	    let working_copy_factories = default_working_copy_factories();
474	
475	    let workspace = Workspace::load(&settings, path, &store_factories, &working_copy_factories)?;
476	    let repo = workspace.repo_loader().load_at_head().block_on()?;
477	
478	    Ok((workspace, repo))
479	}
480	
481	/// Parse and evaluate a revset string, returning commit IDs.
482	pub fn resolve_revset(
483	    workspace: &Workspace,
484	    repo: &Arc<ReadonlyRepo>,
485	    revset_str: &str,
486	) -> Result<Vec<CommitId>, Box<dyn std::error::Error>> {
487	    let aliases_map = RevsetAliasesMap::new();
488	    let fileset_aliases_map = FilesetAliasesMap::new();
489	    let extensions = RevsetExtensions::default();
490	    let workspace_root = workspace.workspace_root().to_path_buf();
491	    let path_converter = RepoPathUiConverter::Fs {
492	        cwd: workspace_root.clone(),
493	        base: workspace_root,
494	    };
495	    let workspace_name = workspace.workspace_name();
496	    let workspace_ctx = RevsetWorkspaceContext {
497	        path_converter: &path_converter,
498	        workspace_name,
499	    };
500	    let context = RevsetParseContext {
501	        aliases_map: &aliases_map,
502	        local_variables: HashMap::new(),
503	        user_email: "",
504	        date_pattern_context: chrono::Utc::now().fixed_offset().into(),
505	        default_ignored_remote: None,
506	        fileset_aliases_map: &fileset_aliases_map,
507	        use_glob_by_default: false,
508	        extensions: &extensions,
509	        workspace: Some(workspace_ctx),
510	    };
511	
512	    let mut diagnostics = RevsetDiagnostics::new();
513	    let expression = jj_lib::revset::parse(&mut diagnostics, revset_str, &context)?;
514	
515	    let no_extensions: &[Box<dyn jj_lib::revset::SymbolResolverExtension>] = &[];
516	    let symbol_resolver = SymbolResolver::new(repo.as_ref(), no_extensions);
517	    let resolved = expression.resolve_user_expression(repo.as_ref(), &symbol_resolver)?;
518	    let revset = resolved.evaluate(repo.as_ref())?;
519	
520	    let mut commit_ids = Vec::new();
521	    for result in revset.iter() {
522	        commit_ids.push(result?);
523	    }
524	    Ok(commit_ids)
525	}
