527	/// Scan `jj bookmark list -a <name>` output for non-tracking remote refs.
528	///
529	/// Tracked remotes appear indented (`  @origin: ...`); non-tracking remotes
530	/// appear at column 0 as `<bookmark>@<remote>: ...`. Returns the
531	/// non-tracking remote name if any is found.
532	pub fn find_non_tracking_remote(list_output: &str, bookmark: &str) -> Option<String> {
533	    let prefix = format!("{bookmark}@");
534	    for line in list_output.lines() {
535	        if line.starts_with(&prefix)
536	            && let Some(rest) = line.strip_prefix(&prefix)
537	            && let Some((remote, _)) = rest.split_once(':')
538	        {
539	            return Some(remote.to_string());
540	        }
541	    }
542	    None
543	}
544	
545	/// Verify all remote refs for `bookmark` in `repo` are tracked.
546	///
547	/// Returns `Err` with the exact `jj bookmark track …` remediation command if
548	/// any non-tracking remote ref is found. Used as a preflight by repo-modifying
549	/// commands (sync, push, finalize) and as a post-condition assertion by setup
550	/// commands (init, clone, test-fixture).
551	pub fn verify_tracking(repo: &Path, bookmark: &str) -> Result<(), Box<dyn std::error::Error>> {
552	    let repo_str = repo.to_string_lossy();
553	    let cwd = Path::new(".");
554	    let all = run(
555	        "jj",
556	        &["bookmark", "list", "-a", bookmark, "-R", &repo_str],
557	        cwd,
558	    )?;
559	    if let Some(remote) = find_non_tracking_remote(&all, bookmark) {
560	        return Err(format!(
561	            "bookmark '{bookmark}' has non-tracking remote '{bookmark}@{remote}' — \
562	             run `jj bookmark track {bookmark} --remote={remote} -R {repo_str}` to fix"
563	        )
564	        .into());
565	    }
566	    Ok(())
567	}
568	
569	/// Walk up from `start` to find the workspace root.
570	///
571	/// The workspace root is the directory whose `.vc-config.toml` has
572	/// `path = "/"`. Returns `None` if no such config is found up to the
573	/// filesystem root — the caller is in a "plain old repo" (POR) with
574	/// no vc-x1 workspace metadata.
575	pub fn find_workspace_root_from(start: &Path) -> Option<PathBuf> {
576	    let mut cur = start.to_path_buf();
577	    loop {
578	        let cfg = cur.join(VC_CONFIG_FILE);
579	        if let Ok(map) = toml_simple::toml_load(&cfg)
580	            && toml_simple::toml_get(&map, "workspace.path").map(String::as_str) == Some("/")
581	        {
582	            return Some(cur);
583	        }
584	        cur = cur.parent()?.to_path_buf();
585	    }
586	}
587	
588	/// Cwd-anchored wrapper over [`find_workspace_root_from`].
589	pub fn find_workspace_root() -> Option<PathBuf> {
590	    let cur = std::env::current_dir().ok()?;
591	    find_workspace_root_from(&cur)
592	}
593	
594	/// Resolve the workspace's default `--scope`.
595	///
596	/// Reads `<workspace_root>/.vc-config.toml > [workspace] other-repo`:
597	///
598	/// - dual workspace (non-empty `other-repo`) → `Roles([Code, Bot])`
599	/// - single-repo workspace (missing / empty `other-repo`) → `Roles([Code])`
600	/// - POR (no workspace_root) → `Single(cwd)` — operate on cwd as a
601	///   one-off jj repo, ignoring any workspace context.
602	pub fn default_scope(workspace_root: Option<&Path>, cwd: &Path) -> Scope {
603	    let Some(root) = workspace_root else {
604	        return Scope::Single(cwd.to_path_buf());
605	    };
606	    let cfg = match toml_simple::toml_load(&root.join(VC_CONFIG_FILE)) {
607	        Ok(c) => c,
608	        Err(_) => return Scope::Roles(vec![Side::Code]),
609	    };
610	    match toml_simple::toml_get(&cfg, "workspace.other-repo") {
611	        Some(v) if !v.is_empty() => Scope::Roles(vec![Side::Code, Side::Bot]),
612	        _ => Scope::Roles(vec![Side::Code]),
613	    }
614	}
615	
616	/// Resolve a `Scope` to concrete repo paths.
617	///
618	/// `Roles(...)` arm:
619	///
620	/// - `Side::Code` → `workspace_root` (or cwd's `.` when `workspace_root` is None).
621	/// - `Side::Bot` → `workspace_root.join(other-repo)`.
622	///
623	/// Errors when `Side::Bot` is requested but the workspace doesn't define
624	/// one (POR or single-repo workspace).
625	///
626	/// `Single(p)` arm: returns `vec![p]` directly — no workspace lookup,
627	/// no `other-repo` resolution. The path is whatever the caller stored
628	/// (typically the value the user passed to `--scope=<path>`, or cwd
629	/// from `default_scope`'s POR branch); shell-style expansion (tilde,
630	/// `$VAR`) happens at the parser/consumer boundary, not here.
631	pub fn scope_to_repos(
632	    scope: &Scope,
633	    workspace_root: Option<&Path>,
634	) -> Result<Vec<PathBuf>, Box<dyn std::error::Error>> {
635	    let sides = match scope {
636	        Scope::Roles(v) => v,
637	        Scope::Single(p) => return Ok(vec![p.clone()]),
638	    };
639	    let mut repos = Vec::new();
640	    for side in sides {
641	        match side {
642	            Side::Code => repos.push(
643	                workspace_root
644	                    .map(Path::to_path_buf)
645	                    .unwrap_or_else(|| PathBuf::from(".")),
646	            ),
647	            Side::Bot => {
648	                let root = workspace_root.ok_or(
649	                    "--scope=bot: not in a vc-x1 workspace (no .vc-config.toml with path = \"/\") — drop --scope or use --scope=code",
650	                )?;
651	                let cfg = toml_simple::toml_load(&root.join(VC_CONFIG_FILE))?;
652	                let other = toml_simple::toml_get(&cfg, "workspace.other-repo")
653	                    .filter(|v| !v.is_empty())
654	                    .ok_or(
655	                        "--scope=bot: no other-repo configured. Add `other-repo = \"…\"` to .vc-config.toml to enable dual-repo operations",
656	                    )?;
657	                repos.push(root.join(other));
658	            }
659	        }
660	    }
661	    Ok(repos)
662	}
663	
664	/// Resolve `CommonArgs.repo` + `CommonArgs.scope` into concrete repo paths.
665	///
666	/// The four `CommonArgs` consumers (`chid` / `desc` / `list` / `show`)
667	/// call this at the start of their body to translate the clap surface
668	/// into the `&[PathBuf]` that `for_each_repo` iterates. Behavior matches
669	/// today's defaults plus a composing rule for the new `--scope` flag:
670	///
671	/// - neither flag → `[.]` (today's no-arg default).
672	/// - `-R PATH` alone → `[PATH]` (today's `-R <path>` behavior;
673	///   workspace context not consulted).
674	/// - `-s ROLES` alone → resolves against `find_workspace_root()` —
675	///   the surrounding workspace if there is one, else POR
676	///   (`Side::Code` → `.`, `Side::Bot` → error).
677	/// - `-R PATH -s ROLES` → resolves with `PATH` as the workspace root
678	///   (overrides `find_workspace_root`). This is the composing case;
679	///   e.g. `chid -R ../foo -s bot` queries `../foo/.claude`.
680	///
681	/// `--scope` is keyword-only today (the `parse_scope_roles` value
682	/// parser rejects path forms); the planned `-s <path>` /
683	/// `-s <path>,roles` workspace-root override is a future feature.
684	pub fn resolve_repos(
685	    repo: Option<&Path>,
686	    scope: Option<&Scope>,
687	) -> Result<Vec<PathBuf>, Box<dyn std::error::Error>> {
688	    match (repo, scope) {
689	        (None, None) => Ok(vec![PathBuf::from(".")]),
690	        (Some(p), None) => Ok(vec![p.to_path_buf()]),
691	        (Some(p), Some(s)) => scope_to_repos(s, Some(p)),
692	        (None, Some(s)) => scope_to_repos(s, find_workspace_root().as_deref()),
693	    }
694	}
695	
696	/// Resolved shared params for the read-only commit-query subcommands
697	/// (`chid` / `desc` / `list` / `show`). Built once at the binary edge
698	/// from `CommonArgs` via `TryFrom`; each subcommand's `XxxParams`
699	/// embeds this.
700	///
701	/// - `spec` — resolved `DotSpec` (parsed `..` notation + per-side
702	///   count budget).
703	/// - `header` — resolved inter-repo `Header` (label vs none).
704	/// - `repos` — resolved repo paths (`-R` + `-s` → `Vec<PathBuf>`).
705	#[derive(Debug)]
706	pub struct CommonParams {
707	    pub spec: DotSpec,
708	    pub header: Header,
709	    pub repos: Vec<PathBuf>,
710	}
711	
712	impl TryFrom<&CommonArgs> for CommonParams {
713	    type Error = String;
714	
715	    /// Resolve clap `CommonArgs` into clap-free `CommonParams`: run
716	    /// `resolve_spec` / `resolve_header` / `resolve_repos` at the
717	    /// binary edge. Fallible because `resolve_repos` can fail
718	    /// (workspace lookup, path issues).
719	    fn try_from(a: &CommonArgs) -> Result<Self, String> {
720	        let spec = resolve_spec(a.pos_rev.as_deref(), a.pos_count, &a.revision, a.limit, "@");
721	        let header = resolve_header(&a.label, a.no_label);
722	        let repos = a.resolve_repos().map_err(|e| e.to_string())?;
723	        Ok(CommonParams {
724	            spec,
725	            header,
726	            repos,
727	        })
728	    }
729	}
