177	/// Clone a single repo via `jj git clone --colocate` and verify
178	/// bookmark tracking.
179	///
180	/// - `source` is the clone source (URL or local path).
181	/// - `target_dir` is the destination working repo location.
182	/// - `parent_dir` is the cwd for the `jj git clone` subprocess.
183	///
184	/// `jj git clone --colocate` does git clone + jj init + automatic
185	/// bookmark tracking in one step (unlike colocate-after-bare-git-clone,
186	/// which needs explicit `jj bookmark track`). The `verify_tracking`
187	/// call asserts the post-clone state matches expectations.
188	pub(crate) fn clone_one(
189	    source: &str,
190	    target_dir: &Path,
191	    parent_dir: &Path,
192	) -> Result<(), Box<dyn std::error::Error>> {
193	    let target_str = target_dir
194	        .to_str()
195	        .ok_or("target path is not valid UTF-8")?;
196	    info!("Cloning {source} → {target_str}...");
197	    run(
198	        "jj",
199	        &["git", "clone", "--colocate", source, target_str],
200	        parent_dir,
201	    )?;
202	    crate::common::verify_tracking(target_dir, "main")?;
203	    Ok(())
204	}
