1	//! `vc-x1 clone` — clone a repo (URL or local path) into a workspace.
2	//!
3	//! - Default (no `--por`): dual-repo layout — clones code, derives
4	//!   bot source (`<source>.claude`), clones bot into
5	//!   `<target>/.claude`, creates the Claude Code symlink. Both
6	//!   sides must succeed.
7	//! - `--por`: single repo into `<target>`. No `.claude/`, no
8	//!   symlink.
9	//!
10	//! TARGET shapes (all routed through `parse_target`): URL,
11	//! `owner/name` shorthand, or a local path (`./X`, `/X`, `~/X`,
12	//! `.`, `..`). Path-form is symmetric with `git clone /local/bare.git`
13	//! — useful for fixtures and CI scratch dirs.
14	//!
15	//! `clone_one` and `clone_dual` are `pub(crate)` so init's `-3`
16	//! reshape can reuse them for the "URL exists → clone" preflight
17	//! path (per `notes/chores/chores-08.md > init + clone redesign`).
18	
19	use std::path::Path;
20	
21	use clap::Args;
22	use log::info;
23	
24	use crate::common::run;
25	use crate::context::Context;
26	use crate::options_flags::por::PorFlag;
27	use crate::subcommand::SubcommandRunner;
28	use crate::symlink;
29	use crate::url::{Target, derive_name, derive_session_url, parse_target, resolve_url};
30	
31	/// CLI args for `vc-x1 clone`.
32	#[derive(Args, Debug)]
33	pub struct CloneArgs {
34	    /// Source to clone — URL, owner/name shorthand, or local path.
35	    ///
36	    /// - URL: `git@host:owner/name(.git)?`, `https://...(.git)?`
37	    /// - owner/name shorthand: resolves to
38	    ///   `git@github.com:owner/name.git`
39	    /// - Local path: `./X`, `../X`, `/X`, `~/X`, `~`, `.`, `..`
40	    ///   (passed directly to `git clone`)
41	    #[arg(value_name = "TARGET", verbatim_doc_comment)]
42	    pub target: String,
43	
44	    /// Destination dir name in cwd [default: derived from TARGET]
45	    #[arg(value_name = "NAME")]
46	    pub name: Option<String>,
47	
48	    /// Flatten of the shared [`PorFlag`] leaf — `--por` switches
49	    /// the clone shape from dual (default) to single repo.
50	    #[command(flatten)]
51	    pub por: PorFlag,
52	
53	    /// Dry run — show what would be done without executing.
54	    #[arg(long)]
55	    pub dry_run: bool,
56	}
57	
58	/// Inputs to the clone op, flat, owned, clap-free.
59	///
60	/// - `target`: the `TARGET` positional (URL, `owner/name`, or
61	///   local path).
62	/// - `name`: optional `NAME` positional override for the
63	///   destination dir.
64	/// - `por`: `--por` resolved — `true` for plain single repo,
65	///   `false` (default) for dual.
66	/// - `dry_run`: `--dry-run`.
67	pub struct CloneParams {
68	    pub target: String,
69	    pub name: Option<String>,
70	    pub por: bool,
71	    pub dry_run: bool,
72	}
73	
74	impl From<&CloneArgs> for CloneParams {
75	    /// Convert clap-derived `CloneArgs` into the flat `CloneParams`
76	    /// (total — every field copies straight over).
77	    fn from(a: &CloneArgs) -> Self {
78	        Self {
79	            target: a.target.clone(),
80	            name: a.name.clone(),
81	            por: a.por.value,
82	            dry_run: a.dry_run,
83	        }
84	    }
85	}
86	
87	impl SubcommandRunner for CloneArgs {
88	    type Params = CloneParams;
89	
90	    /// Delegate to the existing `From<&CloneArgs>` impl above
91	    /// (total — never fails).
92	    fn to_params(&self) -> Result<Self::Params, String> {
93	        Ok(CloneParams::from(self))
94	    }
95	
96	    /// Run the existing `clone_repo` op.
97	    fn run(ctx: &Context, params: &Self::Params) -> Result<(), Box<dyn std::error::Error>> {
98	        clone_repo(ctx, params)
99	    }
100	}
101	
102	/// Top-level clone driver.
103	///
104	/// - Resolves TARGET to a concrete clone source (URL or path).
105	/// - Determines destination dir name (`[NAME]` override or
106	///   `derive_name(TARGET)`).
107	/// - Pre-checks target dir doesn't exist.
108	/// - Dispatches to `clone_one` (POR) or `clone_dual` (code,bot).
109	///
110	/// `ctx` is unused today (clone reads neither user config nor the
111	/// `--log` path); it's present for the uniform subcommand-layer
112	/// signature.
113	pub fn clone_repo(_ctx: &Context, params: &CloneParams) -> Result<(), Box<dyn std::error::Error>> {
114	    log::debug!("clone: enter");
115	
116	    let parsed = parse_target(&params.target)?;
117	    let source = match parsed {
118	        Target::Url(u) => u,
119	        Target::OwnerName(o, n) => resolve_url(&format!("{o}/{n}")),
120	        Target::Path(p) => p.to_str().ok_or("path is not valid UTF-8")?.to_string(),
121	        Target::BareName(n) => {
122	            return Err(format!(
123	                "'{n}' is a bare name — clone has no config-driven defaults; \
124	                 use 'owner/{n}', a full URL, or './{n}' for a local path"
125	            )
126	            .into());
127	        }
128	    };
129	
130	    let name = match &params.name {
131	        Some(n) => n.clone(),
132	        None => derive_name(&params.target)?,
133	    };
134	    let parent_dir = std::env::current_dir()?;
135	    let project_dir = parent_dir.join(&name);
136	
137	    if project_dir.exists() {
138	        return Err(format!("'{}' already exists", project_dir.display()).into());
139	    }
140	
141	    if params.dry_run {
142	        info!("Dry run — would execute:");
143	        if params.por {
144	            info!("  1. jj git clone --colocate {source} {name}");
145	        } else {
146	            let session_source = derive_session_url(&source);
147	            info!("  1. jj git clone --colocate {source} {name}");
148	            info!("  2. jj git clone --colocate {session_source} {name}/.claude");
149	            info!("  3. Create Claude Code symlink");
150	        }
151	        return Ok(());
152	    }
153	
154	    run("jj", &["--version"], Path::new(".")).map_err(|_| "jj is not installed")?;
155	
156	    if params.por {
157	        clone_one(&source, &project_dir, &parent_dir)?;
158	        info!("");
159	        info!("Done! Project cloned to {}", project_dir.display());
160	        info!("  Code repo: {}", project_dir.display());
161	    } else {
162	        clone_dual(&source, &project_dir, &parent_dir)?;
163	    }
164	
165	    log::debug!("clone: exit");
166	    Ok(())
167	}
168	
169	/// Clone a single repo via `jj git clone --colocate` and verify
170	/// bookmark tracking.
171	///
172	/// - `source` is the clone source (URL or local path).
173	/// - `target_dir` is the destination working repo location.
174	/// - `parent_dir` is the cwd for the `jj git clone` subprocess.
175	///
176	/// `jj git clone --colocate` does git clone + jj init + automatic
177	/// bookmark tracking in one step (unlike colocate-after-bare-git-clone,
178	/// which needs explicit `jj bookmark track`). The `verify_tracking`
179	/// call asserts the post-clone state matches expectations.
180	pub(crate) fn clone_one(
181	    source: &str,
182	    target_dir: &Path,
183	    parent_dir: &Path,
184	) -> Result<(), Box<dyn std::error::Error>> {
185	    let target_str = target_dir
186	        .to_str()
187	        .ok_or("target path is not valid UTF-8")?;
188	    info!("Cloning {source} → {target_str}...");
189	    run(
190	        "jj",
191	        &["git", "clone", "--colocate", source, target_str],
192	        parent_dir,
193	    )?;
194	    crate::common::verify_tracking(target_dir, "main")?;
195	    Ok(())
196	}
197	
198	/// Orchestrate a dual-repo clone: code via `clone_one`, bot via
199	/// `clone_one` (no graceful skip — both sides required by the
200	/// default dual shape; users who want code-only pass `--por`),
201	/// then create the Claude Code symlink.
202	pub(crate) fn clone_dual(
203	    code_source: &str,
204	    target_dir: &Path,
205	    parent_dir: &Path,
206	) -> Result<(), Box<dyn std::error::Error>> {
207	    let session_source = derive_session_url(code_source);
208	    let session_dir = target_dir.join(".claude");
209	
210	    clone_one(code_source, target_dir, parent_dir)?;
211	    clone_one(&session_source, &session_dir, target_dir)?;
212	    info!("Creating Claude Code symlink...");
213	    let sl = symlink::install(target_dir)?;
214	
215	    info!("");
216	    info!("Done! Project cloned to {}", target_dir.display());

