1	//! Shared test helpers for dual-repo integration tests.
2	//!
3	//! Provides a `Fixture` that wraps `crate::init::init`
4	//! plus a per-process unique-tempdir helper so parallel tests don't
5	//! collide. Lifted out of the `sync` test module (originally inline at
6	//! `sync.rs:521–560`) so `push`'s tests (0.37.0) and any future
7	//! subcommand's tests can sit on the same harness without
8	//! copy-paste drift.
9	//!
10	//! Test-only — the whole module is gated at its declaration site via
11	//! `#[cfg(test)] mod test_helpers;`.
12	
13	use std::fs;
14	use std::path::PathBuf;
15	use std::sync::atomic::{AtomicU64, Ordering};
16	use std::time::{SystemTime, UNIX_EPOCH};
17	
18	use crate::common::write_file;
19	use crate::config::RepoSelector;
20	use crate::context::Context;
21	use crate::init::{InitArgs, InitParams, init};
22	use crate::options_flags::account::AccountOption;
23	use crate::options_flags::config::ConfigOption;
24	use crate::options_flags::por::PorFlag;
25	use crate::options_flags::provision_bundle::ProvisionOptionFlagBundle;
26	use crate::options_flags::repo::RepoOption;
27	use crate::options_flags::use_template::UseTemplateOption;
28	use crate::test_tmp_root::{resolve_tmp_root, should_keep_tempdir};
29	
30	/// Per-process counter so same-nanosecond tempdir collisions yield
31	/// distinct paths when tests run in parallel.
32	static COUNTER: AtomicU64 = AtomicU64::new(0);
33	
34	/// Build a unique tempdir path for a test fixture.
35	///
36	/// Combines a nanosecond timestamp with a per-process atomic counter
37	/// so parallel tests and same-nanosecond collisions both yield
38	/// distinct paths. Prefix is `vc-x1-test-<tag>-<ts>-<n>` so callers
39	/// from different subcommand tests stay discoverable in `$TMPDIR`.
40	pub fn unique_base(tag: &str) -> PathBuf {
41	    let ts = SystemTime::now()
42	        .duration_since(UNIX_EPOCH)
43	        .map(|d| d.as_nanos())
44	        .unwrap_or(0); // OK: clock error → 0 is harmless for unique tempdir naming
45	    let n = COUNTER.fetch_add(1, Ordering::SeqCst);
46	    resolve_tmp_root().join(format!("vc-x1-test-{tag}-{ts}-{n}"))
47	}
48	
49	/// Owned dual-repo fixture with RAII cleanup.
50	///
51	/// Builds a fresh throwaway dual-repo set under a unique tempdir
52	/// by driving `init::init` with a path TARGET and `--repo
53	/// local=<base>` (so config lookup is skipped via the
54	/// resolve_repo short-circuit). `create_symlink=false` suppresses
55	/// the `~/.claude/projects/` side effect. Exposes the two repo
56	/// paths (`work` and `work/.claude`). The tempdir tree is removed
57	/// when the value is dropped, so a panicking test still cleans up
58	/// after itself.
59	pub struct Fixture {
60	    /// Root tempdir that owns both repos and their bare-git remotes.
61	    pub base: PathBuf,
62	    /// Code repo path (`<base>/work`).
63	    pub work: PathBuf,
64	    /// Bot session repo path (`<base>/work/.claude`).
65	    pub claude: PathBuf,
66	}
67	
68	impl Fixture {
69	    /// Build a fresh fixture in a unique tempdir.
70	    pub fn new(tag: &str) -> Self {
71	        Self::new_opts(tag, false, None)
72	    }
73	
74	    /// Build a fresh fixture with optional pending changes and a
75	    /// template seed.
76	    ///
77	    /// - `with_pending` — after init, write a small file into each
78	    ///   repo so `@` carries uncommitted changes (useful for
79	    ///   finalize / push tests).
80	    /// - `use_template` — `CODE[,BOT]` forwarded to init.
81	    pub fn new_opts(tag: &str, with_pending: bool, use_template: Option<String>) -> Self {
82	        let base = unique_base(tag);
83	        // init refuses to reuse an existing project_dir, so `base`
84	        // must not exist yet. `unique_base` already guarantees that.
85	        //
86	        // Path TARGET = `<base>/work` (workspace destination); the
87	        // basename ("work") becomes the repo name. `--repo local=<base>`
88	        // sets the bare-repo parent so the layout mirrors the old
89	        // `--repo-local <base>` + NAME=`work` shape:
90	        //   <base>/work/                  (code repo)
91	        //   <base>/work/.claude/          (bot session repo)
92	        //   <base>/remote-code.git        (code bare origin)
93	        //   <base>/remote-claude.git      (bot bare origin)
94	        let work_path = base.join("work");
95	        let args = InitArgs {
96	            target: work_path.to_string_lossy().into_owned(),
97	            name: None,
98	            account: AccountOption::default(),
99	            repo: RepoOption {
100	                repo: Some(RepoSelector {
101	                    category: "local".to_string(),
102	                    value: Some(base.to_string_lossy().into_owned()),
103	                }),
104	            },
105	            por: PorFlag { value: false },
106	            provision: ProvisionOptionFlagBundle::default(),
107	            use_template: UseTemplateOption { use_template },
108	            config: ConfigOption::default(),
109	        };
110	        let ctx = Context::load(None).expect("load user config for test fixture");
111	        let mut params = InitParams::from(&args);
112	        params.create_symlink = false;
113	        init(&ctx, &params).expect("build test fixture via init");
114	
115	        let work = base.join("work");
116	        let claude = work.join(".claude");
117	
118	        if with_pending {
119	            write_file(&work.join("TODO.md"), "# TODO\n- first feature\n")
120	                .expect("write pending TODO.md");
121	            write_file(
122	                &claude.join("session-notes.md"),
123	                "# Session notes\n- simulated pending work\n",
124	            )
125	            .expect("write pending session-notes.md");
126	        }
127	
128	        Fixture { base, work, claude }
129	    }
130	
131	    /// Convenience: return both repo paths as a `Vec<PathBuf>`
132	    /// suitable for `sync_repos` (or any other `&[PathBuf]` API).
133	    pub fn repos(&self) -> Vec<PathBuf> {
134	        vec![self.work.clone(), self.claude.clone()]
135	    }
136	}
137	
138	impl Drop for Fixture {
139	    /// Remove the fixture tree on drop. Best-effort; a failure here
140	    /// doesn't fail the test. Suppressed when `$VC_X1_TEST_KEEP` is
141	    /// set — see `test_tmp_root::should_keep_tempdir`.
142	    fn drop(&mut self) {
143	        if should_keep_tempdir() {
144	            eprintln!("VC_X1_TEST_KEEP set; preserving {}", self.base.display());
145	        } else {
146	            let _ = fs::remove_dir_all(&self.base);
147	        }
148	    }
149	}
150	
151	/// Owned single-repo (POR) fixture with RAII cleanup.
152	///
153	/// Sibling of `Fixture` for `--por` flows. Drives
154	/// `init::init` with `por: true` and a path TARGET;
