87	/// Run a command with retries, sleeping between attempts.
88	fn run_retry(
89	    cmd: &str,
90	    args: &[&str],
91	    cwd: &Path,
92	    retry: &PushRetryOptions,
93	) -> Result<String, Box<dyn std::error::Error>> {
94	    let mut last_err = String::new();
95	    for attempt in 1..=retry.push_retries {
96	        match run(cmd, args, cwd) {
97	            Ok(out) => {
98	                if attempt > 1 {
99	                    debug!("succeeded after {attempt} attempts");
100	                }
101	                return Ok(out);
102	            }
103	            Err(e) => {
104	                last_err = e.to_string();
105	                if attempt < retry.push_retries {
106	                    debug!(
107	                        "attempt {attempt}/{} failed: {last_err}",
108	                        retry.push_retries
109	                    );
110	                    debug!("retrying in {}s...", retry.push_retry_delay);
111	                    std::thread::sleep(std::time::Duration::from_secs(retry.push_retry_delay));
112	                }
113	            }
114	        }
115	    }
116	    Err(format!("failed after {} attempts: {last_err}", retry.push_retries).into())
117	}
